package com.careeros.resume.domain;
import com.careeros.common.domain.AuditableEntity;import com.careeros.job.domain.JobPosting;import jakarta.persistence.*;import org.hibernate.annotations.UuidGenerator;import java.time.Instant;import java.util.UUID;
@Entity @Table(name="resume_versions") public class ResumeVersion extends AuditableEntity{
 @Id @UuidGenerator private UUID id;@Column(nullable=false,unique=true)private int versionNumber;@Enumerated(EnumType.STRING)@Column(nullable=false)private Type type;@Enumerated(EnumType.STRING)@Column(nullable=false)private Status status;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="job_posting_id")private JobPosting job;@Column(name="application_id")private UUID applicationId;private String modelUsed;private String promptVersion;private Long generationDurationMs;private String validationResult;@Column(columnDefinition="text")private String validationWarnings;@Column(columnDefinition="text")private String generatedBullets;@Column(length=2048)private String docxPath;@Column(length=2048)private String pdfPath;private boolean pdfGenerated;private boolean archived;private Instant downloadedAt;protected ResumeVersion(){}
 public static ResumeVersion generating(int number,JobPosting job,UUID application,String model,String prompt){var v=new ResumeVersion();v.versionNumber=number;v.type=Type.GENERATED;v.status=Status.GENERATING;v.job=job;v.applicationId=application;v.modelUsed=model;v.promptVersion=prompt;return v;}
 public void complete(long duration,String validation,String warnings,String bullets,String docx,String pdf){generationDurationMs=duration;validationResult=validation;validationWarnings=warnings;generatedBullets=bullets;docxPath=docx;pdfPath=pdf;pdfGenerated=pdf!=null;status=Status.READY;}public void fail(long duration,String warning){generationDurationMs=duration;validationResult="FAILED";validationWarnings=warning;status=Status.FAILED;}public void archive(){archived=true;status=Status.ARCHIVED;}public void restore(){archived=false;status=Status.READY;}public void downloaded(){downloadedAt=Instant.now();}
 public enum Type{MASTER,GENERATED}public enum Status{GENERATING,READY,FAILED,ARCHIVED}public UUID getId(){return id;}public int getVersionNumber(){return versionNumber;}public Type getType(){return type;}public Status getStatus(){return status;}public JobPosting getJob(){return job;}public UUID getApplicationId(){return applicationId;}public String getModelUsed(){return modelUsed;}public String getPromptVersion(){return promptVersion;}public Long getGenerationDurationMs(){return generationDurationMs;}public String getValidationResult(){return validationResult;}public String getValidationWarnings(){return validationWarnings;}public String getGeneratedBullets(){return generatedBullets;}public String getDocxPath(){return docxPath;}public String getPdfPath(){return pdfPath;}public boolean isPdfGenerated(){return pdfGenerated;}public boolean isArchived(){return archived;}public Instant getDownloadedAt(){return downloadedAt;}
}
